// History.jsx — No backend logic, navigation only
import React from "react";
import { useNavigate } from "react-router-dom";

const green = "#0f9d58";
const lightGreen = "#eaf8f0";

export default function History({ employee }) {
  const navigate = useNavigate();

  if (!employee) {
    return (
      <div style={centerScreen}>
        <div>Employee data not found. Please login again.</div>
      </div>
    );
  }

  return (
    <div style={outer}>
      <div style={card}>
        <div style={headerRow}>
          <button onClick={() => navigate("/profile")} style={backBtn}>⬅ Back</button>
          <h2 style={headerTitle}>History</h2>
        </div>

        <p style={subText}>Employee: {employee.name} • {employee.empld}</p>

        <div style={cardsWrapper}>
          <div style={historyCard} onClick={() => navigate("/travel-history")}>
            <div>
              <h3 style={title}>Travel Expense History</h3>
              <p style={desc}>View, filter, edit & delete travel records</p>
            </div>
            <div style={arrow}>›</div>
          </div>

          <div style={historyCard} onClick={() => navigate("/ticket-history")}>
            <div>
              <h3 style={title}>Ticket Expense History</h3>
              <p style={desc}>View & manage ticket expenses</p>
            </div>
            <div style={arrow}>›</div>
          </div>

          <div style={historyCard} onClick={() => navigate("/bills-history")}>
            <div>
              <h3 style={title}>Bills Upload History</h3>
              <p style={desc}>View uploaded bills & receipts</p>
            </div>
            <div style={arrow}>›</div>
          </div>
        </div>
      </div>
    </div>
  );
}

// Styles
const outer = { minHeight: "100vh", background: lightGreen, padding: 20, fontFamily: "Segoe UI" };
const centerScreen = { ...outer, display: "flex", alignItems: "center", justifyContent: "center" };
const card = { maxWidth: 900, margin: "0 auto", background: "#fff", borderRadius: 16, padding: 20, boxShadow: "0 6px 20px rgba(0,0,0,0.12)" };
const backBtn = { background: "transparent", border: "none", color: green, fontSize: 16, cursor: "pointer" };
const headerRow = { display: "flex", alignItems: "center", gap: 10 };
const headerTitle = { margin: 0, color: green };
const subText = { fontSize: 13, color: "#555", marginTop: 6 };
const cardsWrapper = { marginTop: 20, display: "flex", flexDirection: "column", gap: 18 };
const historyCard = { background: "#fff", border: "1px solid #eaf8f0", borderRadius: 14, padding: 18, display: "flex", justifyContent: "space-between", cursor: "pointer", boxShadow: "0 2px 10px rgba(0,0,0,0.05)" };
const title = { margin: 0, color: green, fontSize: 18 };
const desc = { margin: "4px 0 0", fontSize: 13, color: "#666" };
const arrow = { fontSize: 30, color: green, fontWeight: "bold" };
